1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOWUP_DISCOUNT_RATE = 0.15;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	type Item = {
21	  type: string;
22	  material?: string;
23	  enchantment?: number;
24	  cursed?: boolean;
25	};
26	type Step = { op: "quote"; items: Item[] };
27	type Customer = { yearsWithMHPCO: number; firstQuote?: boolean };
28	type Scenario = { customer: Customer; steps: Step[] };
29	
30	const componentGroupPremium = (count: number): number =>
31	  count === COMPONENT_BLOCK_SIZE
32	    ? COMPONENT_BLOCK_PREMIUM
33	    : count * COMPONENT_BASE_PREMIUM;
34	
35	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
36	
37	const isHighEnchantment = (item: Item): boolean =>
38	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
39	
40	const qualifiesForFirstInsurance = (item: Item, isSingleItemPolicy: boolean): boolean =>
41	  isSingleItemPolicy && !!item.cursed && !isHighEnchantment(item);
42	
43	const surchargeRates = (item: Item, isSingleItemPolicy: boolean): number[] => [
44	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
45	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
46	  qualifiesForFirstInsurance(item, isSingleItemPolicy) ? FIRST_INSURANCE_RATE : 0,
47	];
48	
49	const mainItemPremium = (item: Item, isSingleItemPolicy: boolean): number => {
50	  const base = BASE_PREMIUM_BY_TYPE[item.type];
51	  const totalRate = surchargeRates(item, isSingleItemPolicy).reduce((a, b) => a + b, 1);
52	  return base * totalRate;
53	};
54	
55	const countByType = (items: Item[]): Map<string, number> =>
56	  items.reduce(
57	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
58	    new Map<string, number>(),
59	  );
60	
61	const sumComponentPremiums = (components: Item[]): number =>
62	  [...countByType(components).values()]
63	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
64	
65	const partitionItems = (items: Item[]): { mains: Item[]; components: Item[] } =>
66	  items.reduce<{ mains: Item[]; components: Item[] }>(
67	    (acc, item) => {
68	      (isMainItem(item) ? acc.mains : acc.components).push(item);
69	      return acc;
70	    },
71	    { mains: [], components: [] },
72	  );
73	
74	const sumItemPremiums = (items: Item[]): number => {
75	  const { mains, components } = partitionItems(items);
76	  const isSingleItemPolicy = items.length === 1;
77	  const mainsSum = mains.reduce((sum, item) => sum + mainItemPremium(item, isSingleItemPolicy), 0);
78	  return mainsSum + sumComponentPremiums(components);
79	};
80	
81	const customerRateAdjustments = (customer: Customer, stepIndex: number): number[] => [
82	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT_RATE : 0,
83	  customer.firstQuote ? FIRST_INSURANCE_RATE : 0,
84	  stepIndex > 0 ? -FOLLOWUP_DISCOUNT_RATE : 0,
85	];
86	
87	const policyWideRate = (customer: Customer, stepIndex: number): number =>
88	  customerRateAdjustments(customer, stepIndex).reduce((sum, rate) => sum + rate, 0);
89	
90	const ceilInFavor = (value: number): number => Math.ceil(Number(value.toFixed(6)));
91	
92	const quotePremiumFor = (step: Step, customer: Customer, stepIndex: number): { premium: number } => ({
93	  premium: ceilInFavor(sumItemPremiums(step.items) * (1 + policyWideRate(customer, stepIndex)) + PROCESSING_FEE),
94	});
95	
96	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
97	  results: scenario.steps.map((step, i) => quotePremiumFor(step, scenario.customer, i)),
98	});
